        "discloser_country_or_area": "India",
        "public_status": "Public",
        "question_number": "Q6.1.1",
        "question_text": "Provide details of your emissions reduction target(s). Please report both long-term and mid-term targets, if applicable.",
        "row_order": 1,
        "row_name": "Row 1",
        "col1_Select a reference ID for the target": "Target 1",
        "col2_Target type^": "Baseline scenario target",
        "col3_Boundary of target relative to jurisdiction boundary^": "Same - covers entire jurisdiction and nothing else",
